"use client";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  Legend,
} from "recharts";

export default function ExpenseGraph({ expenses = [] }) {
  const categoryColors = {
    Mat: "#FF8042",
    Hem: "#0088FE",
    Nöje: "#00C49F",
    Transport: "#FFBB28",
    Shopping: "#8884d8",
    Övrigt: "#cccccc",
  };

  const now = new Date();
  const daysInMonth = new Date(
    now.getFullYear(),
    now.getMonth() + 1,
    0,
  ).getDate();

  const monthlyData = Array.from({ length: daysInMonth }, (_, i) => ({
    day: i + 1,
  }));

  expenses.forEach((exp) => {
    const expDate = new Date(exp.date);

    if (
      expDate.getMonth() === now.getMonth() &&
      expDate.getFullYear() === now.getFullYear()
    ) {
      const dayIndex = expDate.getDate() - 1;
      const cat = exp.category || "Övrigt";

      if (dayIndex >= 0 && dayIndex < daysInMonth) {
        monthlyData[dayIndex][cat] =
          (monthlyData[dayIndex][cat] || 0) + Number(exp.amount);
      }
    }
  });

  return (
    <div className="chart">
      <h3>Monthly Expenses</h3>
      <br />
      <div style={{ width: "100%", height: 300, fontSize: ".78em" }}>
        <ResponsiveContainer key={expenses.length}>
          <p style={{color:"grey", paddingLeft:"15px"}}>Kr</p>
          <BarChart
            data={monthlyData}
            margin={{ left: -20, right: 20, top: 20, bottom: 5 }}
          >
            <XAxis
              dataKey="day"
              label={{ value: "Days", position: "insideBottom", offset: -5 }}
            />
            <YAxis
              label={{ value: "kr", angle: 20, position: "left", offset: 10 }}
            />
            <Tooltip />
            {Object.keys(categoryColors).map((cat) => (
              <Bar
                key={cat}
                dataKey={cat}
                fill={categoryColors[cat]}
                barSize={15}
              />
            ))}
          </BarChart>
        </ResponsiveContainer>
      </div>
      {/* Lägg legend utanför grafen */}
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          gap: "15px",
          marginTop: "25px",
          flexWrap: "wrap",
        }}
      >
        {Object.keys(categoryColors).map((cat) => (
          <div
            key={cat}
            style={{
              display: "flex",
              alignItems: "center",
              gap: "5px",
              color: "white",
            }}
          >
            <div
              style={{
                width: 12,
                height: 12,
                backgroundColor: categoryColors[cat],
                borderRadius: 2,
              }}
            />
            <span style={{ fontSize: "0.78em" }}>{cat}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
